export function toposort(graph: Map<string, string[]>): string[] {
  const visited = new Map<string, 'unvisited' | 'visiting' | 'visited'>();
  const result: string[] = [];

  // Initialize all nodes as unvisited
  for (const node of graph.keys()) {
    visited.set(node, 'unvisited');
  }

  function dfs(node: string): void {
    const state = visited.get(node) || 'unvisited';

    if (state === 'visiting') {
      throw new Error(`Cycle detected at node: ${node}`);
    }

    if (state === 'visited') {
      return;
    }

    visited.set(node, 'visiting');

    const neighbors = graph.get(node) || [];
    for (const neighbor of neighbors) {
      dfs(neighbor);
    }

    visited.set(node, 'visited');
    result.push(node);
  }

  for (const node of graph.keys()) {
    if (visited.get(node) === 'unvisited') {
      dfs(node);
    }
  }

  return result.reverse();
}
```

